<div class="card"><div class="meta">Inbound email endpoint: <code>public/email_ingest.php</code> · Auth token stored in <code>support_ingest_token</code> setting.</div><table><thead><tr><th>ID</th><th>Ticket</th><th>Priority</th><th>Status</th><th>Owner</th><th>SLA</th><th>Due</th><th>Actions</th></tr></thead><tbody><?php foreach ($tickets as $ticket): ?><tr><td><?= e((string)$ticket['id']) ?></td><td><strong><?= e($ticket['title']) ?></strong><div class="meta"><?= e($ticket['category_name']) ?> · <?= e((string)($ticket['detail_text'] ?? '')) ?></div><div class="meta">Requester: <?= e((string)($ticket['requester_name'] ?? 'Unknown')) ?><?= !empty($ticket['requester_email']) ? ' · ' . e((string)$ticket['requester_email']) : '' ?> · Source: <?= e((string)($ticket['source_channel'] ?? 'Web')) ?><?= !empty($ticket['thread_ref']) ? ' · Thread: ' . e((string)$ticket['thread_ref']) : '' ?></div><?php $renderThread($commentsByTicket[(int)$ticket['id']] ?? []); ?></td><td><span class="tag"><?= e($ticket['priority_name']) ?></span></td><td><?= e($ticket['status_name']) ?></td><td><?= e((string)($ticket['owner_name'] ?? 'Unassigned')) ?></td><td><?= e((string)($ticket['sla_policy_name'] ?? '—')) ?></td><td><?php if (!empty($ticket['resolution_due_at'])): ?><span class="<?= (strtotime((string)$ticket['resolution_due_at']) < time() && !in_array($ticket['status_name'], ['Resolved','Closed'], true)) ? 'tag tag-danger' : 'tag' ?>"><?= e($ticket['resolution_due_at']) ?></span><?php else: ?>—<?php endif; ?></td><td><?php if (\App\Core\Auth::can('support','edit')): ?><form method="post" style="display:inline-block"><?= csrf_field() ?><input type="hidden" name="action" value="status"><input type="hidden" name="id" value="<?= e((string)$ticket['id']) ?>"><select name="status_name"><?php foreach (['Open','Investigating','Waiting','Escalated','Resolved','Closed'] as $status): ?><option value="<?= e($status) ?>" <?= $ticket['status_name'] === $status ? 'selected' : '' ?>><?= e($status) ?></option><?php endforeach; ?></select><button type="submit">Save</button></form><form method="post" class="stack-form" style="margin-top:8px"><?= csrf_field() ?><input type="hidden" name="action" value="comment"><input type="hidden" name="ticket_id" value="<?= e((string)$ticket['id']) ?>"><select name="parent_comment_id"><option value="0">Reply to ticket</option><?php foreach (($commentsByTicket[(int)$ticket['id']] ?? []) as $comment): ?><option value="<?= e((string)$comment['id']) ?>">Comment #<?= e((string)$comment['id']) ?> · <?= e(substr((string)$comment['comment_text'], 0, 40)) ?></option><?php endforeach; ?></select><select name="visibility_scope"><?php foreach (['internal' => 'Internal', 'client' => 'Client Visible'] as $v => $label): ?><option value="<?= e($v) ?>"><?= e($label) ?></option><?php endforeach; ?></select><textarea name="comment_text" rows="3" placeholder="Add a threaded ticket reply" required></textarea><?php if (!empty($ticket['requester_email'])): ?><label><input type="checkbox" name="send_email_reply" value="1"> Queue email reply to requester</label><?php endif; ?><button type="submit">Add Reply</button></form><?php endif; ?> <?php if (\App\Core\Auth::can('support','delete')): ?><form method="post" style="display:inline-block" onsubmit="return confirm('Delete this ticket?')"><?= csrf_field() ?><input type="hidden" name="action" value="delete"><input type="hidden" name="id" value="<?= e((string)$ticket['id']) ?>"><button type="submit">Delete</button></form><?php endif; ?></td></tr><?php endforeach; ?></tbody></table></div>
